public class LogActionFilter : IActionFilter
{
    private readonly ILogger<LogActionFilter> _log;
    public LogActionFilter(ILogger<LogActionFilter> log) => _log = log;
    public void OnActionExecuting(ActionExecutingContext c) => _log.LogInformation("Before {A}", c.ActionDescriptor.DisplayName);
    public void OnActionExecuted(ActionExecutedContext c) => _log.LogInformation("After");
}

